sys_script_client.script:
function onLoad() {
    //console.log("onLoad started");

    var ga = new GlideAjax('DynamicDropdownAPI');

    ga.addParam('sysparm_name', 'getParentValues');  
    ga.getXMLAnswer(function(response) {       

        if (!response) {
            alert("No data returned");
            return;
        }

        var countries = JSON.parse(response);

        g_form.clearOptions('country');
        g_form.addOption('country', '', '-- Select Country --');

        for (var i = 0; i < countries.length; i++) {
            g_form.addOption('country', countries[i], countries[i]);
        }
    });
}
